#include <stdio.h>
#include <string.h>

void trim_newline(char *s){size_t n=strlen(s);if(n&&s[n-1]=='\n')s[n-1]='\0';}

int main(){int T; if(scanf("%d",&T)!=1) return 0; getchar(); // consume '\n' after T
    for(int tc=0; tc<T; ++tc){
        char line[256];
        if(!fgets(line,sizeof(line),stdin)) break;
        trim_newline(line);
        int L; if(scanf("%d",&L)!=1) L=0; getchar(); // consume '\n' after L
        // split line
        char *token = strtok(line, " ");
        char *result[100];
        int cnt=0;
        while(token){
            if((int)strlen(token) >= L){
                result[cnt++] = token;
            }
            token = strtok(NULL, " ");
        }
        // output Python‑style list
        printf("[");
        for(int i=0;i<cnt;++i){
            printf("'%s'%s", result[i], i+1==cnt? "" : ", ");
        }
        printf("]\n");
    }
    return 0; }

