#!/usr/bin/env python3
import sys

def filter_words(sentence, min_len):
    return (w for w in sentence.split() if len(w) >= min_len)

def main():
    data = sys.stdin.read().splitlines()
    if not data:
        return
    t = int(data[0])
    idx = 1
    out_lines = []
    for _ in range(t):
        sentence = data[idx] if idx < len(data) else ''
        idx += 1
        min_len = int(data[idx]) if idx < len(data) else 0
        idx += 1
        gen = filter_words(sentence, min_len)
        out_lines.append(str(list(gen)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

